export const COUNTRIES: CountryUI[] = (RAW_COUNTRIES as any).map((c: any) => ({
  ...c,
  flag: FLAGS_BY_ISO[c.iso] ?? null,
}));

export function getCountryByIso(iso: string) {
  return COUNTRIES.find((c) => c.iso === iso) ?? null;
}

export function getFlagSource(iso: string) {
  return FLAGS_BY_ISO[iso] ?? null;
}
